/*
 * DCC — Diagnose Sheet Registration  (READ ONLY — makes no changes)
 *
 * Use when a world shows broken / missing sheets — the stripped "name + image"
 * panel, or every sheet gone INCLUDING Foundry's own defaults. It reports which
 * of the three independent sheet layers failed:
 *
 *   1. REGISTRY  — CONFIG.Actor/Item.sheetClasses. Held in memory only, rebuilt
 *      every load from system/module init. If empty/thin, an init-time error
 *      aborted registration — this is NOT a stored setting; check the console
 *      for a red boot error. This is the usual cause of "ALL sheets gone".
 *   2. WORLD DEFAULTS — core.sheetClasses world setting (server-side LevelDB):
 *      the chosen default sheet per document subtype. Entries pointing at a
 *      class that is no longer registered = broken defaults for that subtype.
 *   3. PER-DOCUMENT OVERRIDES — flags.core.sheetClass on individual Actors/Items
 *      (the Item Piles vector). Breaks only the documents that carry the flag.
 *
 * GM only. Output goes to the console (F12) and a summary dialog.
 * https://github.com/foundryvtt-dcc/dcc/issues/777
 */
if (!game.user.isGM) {
  ui.notifications.warn('Only a GM can run the DCC sheet diagnostic.')
  return
}

// --- Layer 1: the in-memory sheet registry --------------------------------
// CONFIG[type].sheetClasses is shaped { subtype: { sheetId: {id, label, ...} } }
function registry (docType) {
  const reg = CONFIG[docType]?.sheetClasses || {}
  const ids = new Set()
  let entries = 0
  for (const subtype of Object.keys(reg)) {
    for (const id of Object.keys(reg[subtype] || {})) { ids.add(id); entries++ }
  }
  return { subtypes: Object.keys(reg).length, entries, ids, raw: reg }
}
const actorReg = registry('Actor')
const itemReg = registry('Item')
const registryThin = actorReg.entries === 0 || itemReg.entries === 0

// --- Layer 2: the world default sheet map (core.sheetClasses) --------------
let worldMap = {}
let worldMapError = null
try {
  worldMap = game.settings.get('core', 'sheetClasses') || {}
} catch (err) {
  worldMapError = err
}
const danglingDefaults = []
for (const [docType, reg] of [['Actor', actorReg], ['Item', itemReg]]) {
  for (const [subtype, cls] of Object.entries(worldMap[docType] || {})) {
    if (typeof cls === 'string' && !reg.ids.has(cls)) {
      danglingDefaults.push({ docType, subtype, cls })
    }
  }
}

// --- Layer 3: per-document overrides (flags.core.sheetClass) ---------------
const overrides = []
for (const [docType, collection, reg] of [
  ['Actor', game.actors, actorReg],
  ['Item', game.items, itemReg]
]) {
  for (const doc of collection) {
    const cls = doc.getFlag('core', 'sheetClass')
    if (typeof cls === 'string' && cls.length) {
      overrides.push({ docType, name: doc.name, id: doc.id, cls, dangling: !reg.ids.has(cls) })
    }
  }
}
const danglingOverrides = overrides.filter(o => o.dangling)

// --- Console dump (the authoritative detail) ------------------------------
console.group('%cDCC — Sheet Registration Diagnostic', 'font-weight:bold;font-size:1.1em')
console.log('Layer 1 — REGISTRY (in-memory, rebuilt every load):')
console.log('  Actor:', actorReg.subtypes, 'subtypes,', actorReg.entries, 'sheet(s):', [...actorReg.ids])
console.log('  Item :', itemReg.subtypes, 'subtypes,', itemReg.entries, 'sheet(s):', [...itemReg.ids])
if (registryThin) console.warn('  ⚠ Registry is EMPTY/THIN — an init error almost certainly aborted sheet registration. Check the console above for a red boot error.')
console.log('Layer 2 — WORLD DEFAULTS (core.sheetClasses world setting):')
if (worldMapError) console.error('  Could not read core.sheetClasses:', worldMapError)
console.log('  raw value:', worldMap)
console.log('  dangling defaults (point at an unregistered class):', danglingDefaults)
console.log('Layer 3 — PER-DOCUMENT OVERRIDES (flags.core.sheetClass):')
console.log('  total documents with an override:', overrides.length)
console.log('  dangling overrides (point at an unregistered class):', danglingOverrides)
console.table(overrides.map(o => ({ type: o.docType, name: o.name, id: o.id, sheet: o.cls, dangling: o.dangling })))
console.groupEnd()

// --- Verdict --------------------------------------------------------------
let verdict
if (registryThin) {
  verdict = '<strong>Layer 1 (registry) failed.</strong> Sheet registration did not complete this load — almost always a JS exception during a module/system <code>init</code>/<code>setup</code> hook. This explains <em>all</em> sheets being gone, including Foundry defaults. <strong>Open the console (F12) and look for the first red error during boot</strong> — disabling the offending module fixes it. No data is corrupt.'
} else if (danglingDefaults.length) {
  verdict = `<strong>Layer 2 (world defaults) is dirty.</strong> ${danglingDefaults.length} default sheet registration(s) point at a class that is not loaded. Those subtypes break; others are fine. The Repair Sheet Overrides macro clears Item Piles entries; for others, reset via Configure Default Sheet.`
} else if (danglingOverrides.length) {
  verdict = `<strong>Layer 3 (per-document overrides).</strong> ${danglingOverrides.length} document(s) carry a sheet override pointing at an unloaded class — only those documents break. Run the Repair Sheet Overrides macro (Item Piles) or clear the flag.`
} else {
  verdict = 'All three layers look healthy: the registry is populated, no world default points at a missing class, and no document override is dangling. If sheets still look wrong it is likely a CSS/render issue or a different flag — capture a console screenshot.'
}

const content = `
  <p>Read-only scan complete. Full detail is in the console (F12).</p>
  <table style="margin:0.5em 0">
    <tr><td><strong>Layer 1 — registry</strong></td>
        <td>Actor: ${actorReg.entries} sheet(s) / ${actorReg.subtypes} subtype(s)<br>
            Item: ${itemReg.entries} sheet(s) / ${itemReg.subtypes} subtype(s)
            ${registryThin ? ' &nbsp;⚠ <strong>EMPTY</strong>' : ''}</td></tr>
    <tr><td><strong>Layer 2 — world defaults</strong></td>
        <td>${danglingDefaults.length} dangling of ${Object.keys(worldMap.Actor || {}).length + Object.keys(worldMap.Item || {}).length} entr(ies)</td></tr>
    <tr><td><strong>Layer 3 — doc overrides</strong></td>
        <td>${overrides.length} override(s), ${danglingOverrides.length} dangling</td></tr>
  </table>
  <hr>
  <p>${verdict}</p>
`

await foundry.applications.api.DialogV2.prompt({
  window: { title: 'DCC — Sheet Registration Diagnostic' },
  content,
  ok: { label: 'Close' },
  rejectClose: false
})
